// Parse pesan dari WhatsApp Trigger node
const data = $input.first().json;

// WhatsApp trigger sudah parse payload Meta otomatis
// Format output: { messages: [...], contacts: [...], metadata: {...} }
const message = data.messages && data.messages[0];
const contact = data.contacts && data.contacts[0];
const metadata = data.metadata || {};

if (!message) {
  return [{ json: { skip: true, reason: 'No message' } }];
}

if (message.type !== 'text') {
  return [{ json: { skip: true, reason: 'Non-text: ' + message.type } }];
}

return [{
  json: {
    skip: false,
    messageId: message.id,
    from: message.from,
    clientName: contact && contact.profile ? contact.profile.name : 'Pelanggan',
    text: message.text && message.text.body ? message.text.body : '',
    timestamp: message.timestamp,
    phoneNumberId: metadata.phone_number_id || '1052743247932102',
    waBusinessId: metadata.display_phone_number || ''
  }
}];

